// Parse and filter Frigate events with smart priority + cooldown dedup
const body = $input.item.json.body || $input.item.json;

// CRITICAL: Only process 'end' events for one notification per detection
const eventType = body.type;
if (eventType !== 'end') {
  return [];
}

const event = body.after || body;
const date = new Date();
const hour = date.getHours();
const nowMs = date.getTime();
const formattedTime = date.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });
const formattedDate = date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });

const isDaytime = hour >= 7 && hour < 22;
const isNight = !isDaytime;

const eventId = event.id;
const camera = event.camera;
const object = event.label;
const score = event.top_score || 0;

// Names match the actual frigate config (domains/media/frigate/parts/config.nix).
// The old map (Front Door/Driveway/Backyard/Carport + a nonexistent
// cobra_cam_4) mislabeled every notification.
const cameraNames = {
  'cobra_cam_1': 'Carport',
  'cobra_cam_2': 'Side Yard',
  'cobra_cam_3': 'Front Porch',
  'reolink': 'Front Yard'
};
const cameraName = cameraNames[camera] || camera;

// Two links: the direct clip (zoned events are retained as alerts, so the
// mp4 always materializes — though finalization can lag the notification by
// up to a minute) and the Frigate UI event page as the always-resolves
// fallback (explore?event_id is supported by the 0.16 web bundle).
const clipUrl = `https://frigate.hwc.iheartwoodcraft.com/api/events/${eventId}/clip.mp4`;
// HLS variant for iOS: the mp4 endpoint streams ffmpeg output chunked with no
// byte-range support, which iPhone AVPlayer refuses; the nginx vod module
// serves the same event as HLS with range support, which iOS plays natively.
const hlsUrl = `https://frigate.hwc.iheartwoodcraft.com/vod/event/${eventId}/master.m3u8`;
const eventUrl = `https://frigate.hwc.iheartwoodcraft.com/explore?event_id=${eventId}`;

// --- Hard filters ---
if (score < 0.6) return [];
if (['plant', 'tree'].includes(object)) return [];

// Zone gate: only events that entered a configured zone notify. Matches
// frigate's own review.alerts.required_zones semantics (street cars and
// sidewalk passersby stay silent — reolink logged 17 zoneless cars in 43min
// one night), and because zoned events are retained as ALERTS (motion, 14d)
// rather than detections (active_objects, effectively clipless), every
// notified event is guaranteed to have recorded footage behind its link.
const zones = event.entered_zones || [];
if (zones.length === 0) return [];
const zone = zones.join(', ');

// Drop daytime cars entirely — never interesting
if (object === 'car' && isDaytime) return [];

// Higher confidence threshold for non-person objects
if (object !== 'person' && score < 0.85) return [];

// --- Cooldown dedup (per camera+object) ---
const staticData = $getWorkflowStaticData('global');
if (!staticData.cooldowns) staticData.cooldowns = {};

// Purge stale entries older than 1 hour
for (const key of Object.keys(staticData.cooldowns)) {
  if (nowMs - staticData.cooldowns[key] > 3600000) {
    delete staticData.cooldowns[key];
  }
}

const cooldownKey = `${camera}:${object}`;
const cooldownMs = object === 'person' ? 120000 : 300000; // 2min person, 5min other

if (staticData.cooldowns[cooldownKey] && (nowMs - staticData.cooldowns[cooldownKey]) < cooldownMs) {
  return []; // Still in cooldown — suppress
}
staticData.cooldowns[cooldownKey] = nowMs;

// --- Priority assignment ---
let priority = 2;
let isPerson = false;

if (object === 'person') {
  isPerson = true;
  priority = isNight ? 5 : 4;
} else if (['car', 'truck'].includes(object) && isNight && camera === 'reolink') {
  // Night vehicle on the front yard. reolink is the ONLY camera that
  // tracks car/truck — the old cobra_cam_3 condition could never fire.
  isPerson = true;
  priority = 5;
} else {
  priority = 2;
}

return [
  {
    json: {
      eventId,
      camera,
      cameraName,
      zone,
      object,
      score,
      priority,
      isPerson,
      isNight,
      clipUrl,
      hlsUrl,
      eventUrl,
      formattedTime,
      formattedDate,
      timestamp: date.toISOString()
    }
  }
];
